-- PC HOTELERÍA — INSERTAR HABITACIONES FALTANTES (SEGURO)
-- Usa ON CONFLICT DO NOTHING → no toca hab. con ocupantes
-- Total a intentar insertar: 1416 hab del MASTER_ROOMS
-- Solo inserta las que NO existen aún por (buildingId, number)
-- ════════════════════════════════════════════════════════

-- PASO 1: Crear índice único temporal si no existe
CREATE UNIQUE INDEX IF NOT EXISTS rooms_building_number_unique
  ON rooms ("buildingId", number);

-- PASO 2: Insertar habitaciones que faltan (idempotente)
ON CONFLICT ("buildingId", number) DO NOTHING;

ON CONFLICT ("buildingId", number) DO NOTHING;

